+      state: "closed" as const,
+      failures: 0,
+      openedAt: 0,
+      cooldown: circuitOptions.cooldown,
+      halfOpenRequests: 0,
+    };
+    circuitStore.circuits.set(origin, circuit);
+
+    const now = Date.now();
+    if (circuit.state === "open") {
+      if (now - circuit.openedAt < circuit.cooldown) {
+        throw new CircuitBreakerOpenError();
+      }
+      circuit.state = "half-open";
+      circuit.halfOpenRequests = 0;
+    }
+    if (
+      circuit.state === "half-open" &&
+      circuit.halfOpenRequests >= circuitOptions.halfOpenMaxRequests
