+    operation.options = circuitOptions;
+    operation.probe = circuit.state === "half-open";
+    if (operation.probe) {
+      circuit.halfOpenRequests++;
+    }
+  }
+
+  function settleCircuit(
+    operation: CircuitOperation,
+    outcome: "success" | "failure" | "neutral"
+  ) {
+    const { circuit, options } = operation;
+    if (!circuit || !options) {
+      return;
+    }
+    if (operation.probe) {
+      circuit.halfOpenRequests--;
+    }
+    if (outcome === "success") {
+      circuit.failures = 0;
+      if (circuit.state === "half-open") {
+        circuit.state = "closed";
+      }
+      return;
+    }
+    if (outcome === "neutral") {
+      return;
+    }
+
