+      circuit.state = "open";
+      circuit.openedAt = Date.now();
+      circuit.cooldown = options.cooldown;
+      return;
+    }
+    circuit.failures++;
+    if (circuit.failures >= options.threshold) {
+      circuit.state = "open";
+      circuit.openedAt = Date.now();
